        downloader.updateProgress(chalk.blue(progressMatch[0]));
      }
    });

    child.stderr.on('data', (data) => {
      const output = data.toString();
      // Extract progress information from Ollama's error output
      const progressMatch = output.match(/(\d+%)/);
      if (progressMatch) {
        downloader.updateProgress(chalk.blue(progressMatch[0]));
      }
    });

    return new Promise((resolve) => {
      child.on('close', (code) => {
        downloader.stop();
        resolve(code === 0);
      });
    });
  } catch (error) {
    downloader.stop();
    console.error(chalk.red(`Failed to install model ${modelName}: ${error.message}`));
    return false;
  }
}
export function startDownloading(modelName) {
  let spinnerFrame = 0;
  let progress = '';
  const spinner = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏'];
  const startTime = Date.now();

  const updateDisplay = () => {
    process.stdout.clearLine(0);
    process.stdout.cursorTo(0);
    process.stdout.write(`${spinner[spinnerFrame]} Installing ${modelName}… ${progress}`);
  };

  // Spinner animation
  const spinnerInterval = setInterval(() => {
    spinnerFrame = (spinnerFrame + 1) % spinner.length;
    updateDisplay();
  }, 80);

  const tick = () => {
    updateDisplay();
  };
  tick();
  const id = setInterval(tick, 1000);
  return {
    stop: () => {
      clearInterval(id);
      clearInterval(spinnerInterval);
      const totalTime = ((Date.now() - startTime) / 1000).toFixed(1);
    },
    updateProgress: (newProgress) => {
      progress = newProgress;
      updateDisplay();
    }
  };
}
export async function ensureModel(model) {
  try {
    // Check if Ollama is installed
    try {
      execSync('which ollama', { stdio: 'ignore' });
    } catch {
      console.error(chalk.red('Ollama CLI not found. Please install Ollama first.'));
      return false;
    }

    // Ensure the model exists
    const models = await readModels();
    if (!models.includes(model)) {
      console.log(chalk.gray(`Model ${model} not found. Installing...`));
      const installed = await installModel(model);
      if (!installed) {
        throw new Error(`Failed to install model: ${model}`);
      }
    }

    return true;
  } catch (error) {
    console.error(chalk.red(`Error ensuring model: ${error.message}`));
    return false;
  }
}

