export function buildErrorTypePrompt(errorOutput, analysis, userContext = '') {
  let prompt = `You are analyzing an error to determine if it's a terminal command issue or a code file issue.

ERROR OUTPUT:
${errorOutput}

ANALYSIS:
${analysis}`;

  if (userContext) {
