  return lines.map((l, i) => {
    // First line keeps original indentation
    if (i === 0) {
      return prefix + l;
    }
    // Subsequent lines get prefix plus base indentation plus content
    return prefix + baseIndent + l;
  }).join('\n') + '\n';
}
