        (text.includes('"') && text.match(/"/g).length >= 2) ||
        (text.includes("'") && text.match(/'/g).length >= 2)
      );

    case 'java': case 'kt': case 'scala':
      // Java/Kotlin/Scala strings
      return (
        (text.includes('"') && text.match(/"/g).length >= 2) ||
        (text.includes("'") && text.match(/'/g).length >= 2)
      );

